// Decky's plugin list icon slot sizes icons via CSS font-size. Font Awesome icons
// obey this because they render <svg width="1em">. An <img> with fixed pixel
// dimensions is ignored by font-size, so the icon stays tiny no matter what size
// you set. The fix: inline the SVG path and use width/height="1em" + fill="currentColor"
// so the icon inherits both size and color from Decky's container — exactly like FA.
// BonsaiLogoIcon (<img>-based) is kept for the tab header where we control the layout.
const BonsaiSvgIcon: React.FC = () => (
  <svg width="1em" height="1em" viewBox="0 0 475 475" fill="currentColor" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
    <path d={BONSAI_SVG_PATH} fillRule="evenodd" />
  </svg>
);

